import unittest
from cache import memoize
class TestCache(unittest.TestCase):
    def test_memo(self):
        self.calls = 0
        @memoize
        def add(a, b):
            self.calls += 1
            return a + b
        add(1, 2); add(1, 2)
        self.assertEqual(self.calls, 1)
